This is my current state, feel free to steal something. It solves initialization and also works when the widget is used in a tabular inline. Other changes were needed to the css, and I want to allow editor configuration from python, so I'm keeping on working on it.

```javascript
(function($) {

    var editors_init = function () {
        if (typeof(jsoneditor) == "undefined")
            jsoneditor = {JSONEditor: JSONEditor};

        $(".for_jsoneditor").each(function (i, v) { init_editor($(v)); });
    };

    var init_editor = function ($f) {
        var id = $f.attr("id") + "_jsoneditor";
        var name = $f.attr("name") + "_jsoneditor";
        if ($f.parents('.empty-form').length) {
            return;
        }
        var $nxt = $f.parent().find('#' + id);
        if ($nxt.attr("name") == name) {
            return;
        }
        var value = {};
        try {
            value = JSON.parse($f[0].value);
        } catch (e) {
            // ignore
        }
        $nxt.detach();
        $nxt = $('<div cols="40" rows="10" id="' + id + '" name="' + name + '"></div>');
        $f.parent().append($nxt);
        var fnc = function (f, nxt, value) {
            var editor = new jsoneditor.JSONEditor(nxt, {
                onChange: function () {
                    f.value = JSON.stringify(editor.get());
                },
                modes: ['tree', 'code'],
                search: true,
            }, value);

            return editor;
        };
        fnc($f[0], $nxt[0], value);
    };

    $(window).on('load', editors_init);

    $(document).on('formset:added', function (e, $row, fs_name) {
        $row.find(".for_jsoneditor").each(
                function (i, v) { init_editor($(v)); });
    });

})(django.jQuery);
```

